"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[4970],{7885(t,e,r){r.r(e),r.d(e,{comp:()=>i,data:()=>n});var a=r(641);const o={},i=(0,r(6262).A)(o,[["render",function(t,e){return(0,a.uX)(),(0,a.CE)("div",null,[...e[0]||(e[0]=[(0,a.Fv)('<h1 id="customer-experience-overview" tabindex="-1"><a class="header-anchor" href="#customer-experience-overview"><span>Customer Experience Overview</span></a></h1><p>What a logged-in customer sees and can do — front-end pages, my-account endpoints, notifications.</p><p><img src="/auctions-for-woocommerce/images/screenshots/front-my-account.png" alt="My Account dashboard — the logged-in customer landing with auction-specific endpoints (My Auctions, Wallet Balance, Watchlist, Withdrawal)"></p><h2 id="my-account-additions" tabindex="-1"><a class="header-anchor" href="#my-account-additions"><span>My Account additions</span></a></h2><p>The plugin adds three new endpoints to <strong>My Account</strong>:</p><table><thead><tr><th>Endpoint</th><th>URL</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="/customer-my-auctions.html" target="_blank" rel="noopener noreferrer">My Auctions</a></td><td><code>/my-account/my-auctions/</code></td><td>Active bids, won, lost, watchlist</td></tr><tr><td><a href="/customer-wallet.html" target="_blank" rel="noopener noreferrer">My Wallet</a></td><td><code>/my-account/my_wallet/</code></td><td>Top up, transfer, view ledger</td></tr><tr><td><a href="/customer-withdrawal.html" target="_blank" rel="noopener noreferrer">Withdrawal</a></td><td><code>/my-account/wkwc_withdrawal/</code></td><td>Request payout</td></tr></tbody></table><p>Plus features integrated into existing tabs:</p><table><thead><tr><th>Existing tab</th><th>Auction-related additions</th></tr></thead><tbody><tr><td>Dashboard</td><td>Active auction summary widget</td></tr><tr><td>Orders</td><td>Order types include auction wins, BIN, wallet top-ups</td></tr><tr><td>Account details</td><td>KYC documents (when <a href="/compliance.html" target="_blank" rel="noopener noreferrer">Compliance</a> is enabled)</td></tr></tbody></table><h2 id="single-auction-page" tabindex="-1"><a class="header-anchor" href="#single-auction-page"><span>Single auction page</span></a></h2><p>The customer-facing page for any auction lives at the linked product&#39;s permalink:</p><p><code>/product/{slug}/</code> (or your storefront&#39;s product permalink structure)</p><p>Components:</p><table><thead><tr><th>Component</th><th>Reference</th></tr></thead><tbody><tr><td><a href="/customer-single-auction.html#bid-form" target="_blank" rel="noopener noreferrer">Bid form</a></td><td>Place / proxy / quick-bid buttons</td></tr><tr><td><a href="/customer-single-auction.html#countdown" target="_blank" rel="noopener noreferrer">Countdown timer</a></td><td>Live, color-coded</td></tr><tr><td><a href="/customer-single-auction.html#badge" target="_blank" rel="noopener noreferrer">Auction badge</a></td><td>Live / Ending Soon / Hot</td></tr><tr><td><a href="/customer-single-auction.html#bid-history" target="_blank" rel="noopener noreferrer">Bid history</a></td><td>Inline or accordion</td></tr><tr><td><a href="/customer-single-auction.html#watchers" target="_blank" rel="noopener noreferrer">Watchers count</a></td><td>Public count</td></tr><tr><td><a href="/reserve-buy-now.html#reserve-indicator" target="_blank" rel="noopener noreferrer">Reserve indicator</a></td><td>Met / Not Met</td></tr><tr><td><a href="/reserve-buy-now.html#buy-it-now" target="_blank" rel="noopener noreferrer">Buy Now button</a></td><td>Optional</td></tr><tr><td><a href="/customer-single-auction.html#gallery" target="_blank" rel="noopener noreferrer">Image gallery</a></td><td>Zoom / lightbox</td></tr><tr><td><a href="/customer-single-auction.html#shipping" target="_blank" rel="noopener noreferrer">Shipping estimator</a></td><td>By postcode</td></tr><tr><td><a href="/social-sharing.html" target="_blank" rel="noopener noreferrer">Share buttons</a></td><td>Social platforms</td></tr><tr><td><a href="#comparison">Comparison</a></td><td>Add to compare</td></tr></tbody></table><p><a href="/customer-single-auction.html" target="_blank" rel="noopener noreferrer">Single auction page reference →</a></p><h2 id="shop-archive" tabindex="-1"><a class="header-anchor" href="#shop-archive"><span>Shop / archive</span></a></h2><p>Auctions appear in the regular shop with a custom badge in the corner:</p><table><thead><tr><th>Badge</th><th>When</th></tr></thead><tbody><tr><td><strong>Live</strong></td><td>Status = active</td></tr><tr><td><strong>Ending Soon</strong></td><td>Within <code>wkafw_urgency_threshold_minutes</code> of close</td></tr><tr><td><strong>New</strong></td><td>Created within last 24 hrs</td></tr><tr><td><strong>Hot</strong></td><td>More than <code>wkafw_hot_auction_threshold</code> bids in last hour</td></tr></tbody></table><p>Filtering by auction type, end date, or price range is available via:</p><ul><li>WooCommerce&#39;s standard product filters</li><li>The <code>[wkafw_auctions]</code> shortcode (custom listing pages)</li><li>Elementor / Gutenberg auction widgets</li></ul><p><a href="/builders.html" target="_blank" rel="noopener noreferrer">Builders →</a>, <a href="/shortcodes.html" target="_blank" rel="noopener noreferrer">Shortcodes →</a></p><h2 id="saved-searches" tabindex="-1"><a class="header-anchor" href="#saved-searches"><span>Saved searches</span></a></h2><p>Customers can save search criteria and get email alerts when matching auctions list.</p><table><thead><tr><th>Setting</th><th>Default</th></tr></thead><tbody><tr><td>Max saved searches per user</td><td>10</td></tr><tr><td>Notification frequency</td><td>Daily digest</td></tr><tr><td>Match check interval</td><td>Hourly cron</td></tr></tbody></table><p>To save a search: on any filtered shop page, click <strong>Save search</strong> → name → confirm.</p><p>Manage at <strong>My Account → Saved Searches</strong>.</p><h2 id="favorites-wishlist" tabindex="-1"><a class="header-anchor" href="#favorites-wishlist"><span>Favorites / Wishlist</span></a></h2><p>Separate from <a href="/watchlist.html" target="_blank" rel="noopener noreferrer">Watchlist</a> — favorites are a personal list, not auction-activity-linked.</p><table><thead><tr><th>Feature</th><th>Watchlist</th><th>Favorites</th></tr></thead><tbody><tr><td>Adds activity emails</td><td>Yes</td><td>No</td></tr><tr><td>Counts toward &quot;watching&quot; psychology</td><td>Yes</td><td>No</td></tr><tr><td>Auto-removes after auction ends</td><td>Yes (7 days)</td><td>No</td></tr><tr><td>Bulk operations</td><td>Yes</td><td>Yes</td></tr><tr><td>Public count</td><td>Yes (per auction)</td><td>No</td></tr></tbody></table><p>Favorites are heart-icon marked. Manage at <strong>My Account → Favorites</strong>.</p><h2 id="comparison" tabindex="-1"><a class="header-anchor" href="#comparison"><span>Comparison</span></a></h2><p>Compare up to 3 auctions side-by-side.</p><ol><li>On any auction, click <strong>Add to compare</strong></li><li>Repeat for up to 2 more lots</li><li>Click the floating compare bar → opens <code>/compare/</code></li><li>Side-by-side table of: image, title, current price, time left, condition, seller, bid count, watchers, BIN price, bid history snapshot</li></ol><p>Useful for buyers deciding between similar lots.</p><h2 id="messaging" tabindex="-1"><a class="header-anchor" href="#messaging"><span>Messaging</span></a></h2><p>Buyer ↔ seller direct messages on individual auctions.</p><table><thead><tr><th>Surface</th><th>Where</th></tr></thead><tbody><tr><td>Auction page</td><td>&quot;Contact seller&quot; button → modal</td></tr><tr><td>Stored in</td><td><code>wkafw_messages</code> table</td></tr><tr><td>Notifications</td><td>Email + in-app badge on My Account</td></tr><tr><td>Threading</td><td>Per-auction conversation thread</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Pre-bid only</p><p>By default, messaging is closed once the user has placed a bid (prevents back-channel collusion). Configurable via <code>wkafw_messaging_post_bid_enabled</code>.</p></div><h2 id="print-auction-details" tabindex="-1"><a class="header-anchor" href="#print-auction-details"><span>Print auction details</span></a></h2><p>A printer-friendly view of an auction is available at <code>/auction/{id}/print/</code>. Used for:</p><ul><li>Estate sale catalogs</li><li>Live event paddles / programs</li><li>Buyer take-home receipts</li></ul><h2 id="share" tabindex="-1"><a class="header-anchor" href="#share"><span>Share</span></a></h2><p>Share buttons inject on every auction page (configurable in <a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a>):</p><ul><li>Facebook</li><li>Twitter / X</li><li>WhatsApp</li><li>Pinterest</li><li>LinkedIn</li><li>Email</li><li>Copy link</li></ul><p><a href="/social-sharing.html" target="_blank" rel="noopener noreferrer">Social Sharing →</a></p><h2 id="notifications" tabindex="-1"><a class="header-anchor" href="#notifications"><span>Notifications</span></a></h2><p>In-app + email + (optionally) SMS / push.</p><table><thead><tr><th>Channel</th><th>Configured at</th><th>Reference</th></tr></thead><tbody><tr><td>Email</td><td>WooCommerce → Settings → Emails</td><td><a href="/notifications.html" target="_blank" rel="noopener noreferrer">Notifications</a></td></tr><tr><td>SMS</td><td>Auctions → Settings → Twilio</td><td><a href="/twilio.html" target="_blank" rel="noopener noreferrer">Twilio</a></td></tr><tr><td>Push</td><td>Auctions → Settings → Firebase</td><td><a href="/firebase.html" target="_blank" rel="noopener noreferrer">Firebase</a></td></tr><tr><td>In-app toast</td><td>Per-auction polling</td><td>(always on)</td></tr></tbody></table><p>Customers manage email preferences at <strong>My Account → Notification preferences</strong>.</p><h2 id="mobile-experience" tabindex="-1"><a class="header-anchor" href="#mobile-experience"><span>Mobile experience</span></a></h2><p>The plugin&#39;s customer surfaces are fully responsive:</p><ul><li>Bid form collapses to single-column on mobile</li><li>Countdown stays prominent</li><li>Touch-friendly buttons (min 44×44 px tap targets)</li><li>Mobile-first poll cadence (slightly slower to save battery)</li></ul><h2 id="accessibility" tabindex="-1"><a class="header-anchor" href="#accessibility"><span>Accessibility</span></a></h2><ul><li>Semantic HTML throughout</li><li>ARIA labels on interactive controls</li><li>Keyboard navigation supported (Tab through bid form)</li><li>Screen-reader announcements on bid placement</li><li>High-contrast mode auto-detected</li></ul><h2 id="templates-to-override" tabindex="-1"><a class="header-anchor" href="#templates-to-override"><span>Templates to override</span></a></h2><p>Customer-facing surfaces can be re-templated by copying to <code>your-theme/auctions-for-woocommerce/</code>:</p><table><thead><tr><th>Template</th><th>Used on</th></tr></thead><tbody><tr><td><code>single-product/bid-form.php</code></td><td>Bid form</td></tr><tr><td><code>single-product/countdown.php</code></td><td>Countdown timer</td></tr><tr><td><code>single-product/auction-info.php</code></td><td>Auction details box</td></tr><tr><td><code>single-product/bid-history.php</code></td><td>Bid history</td></tr><tr><td><code>single-product/auction-badge.php</code></td><td>Single page badge</td></tr><tr><td><code>single-product/penny-auction.php</code></td><td>Penny auction UI</td></tr><tr><td><code>single-product/shipping-estimate.php</code></td><td>Shipping calc</td></tr><tr><td><code>archive/auction-badge.php</code></td><td>Shop / archive badge</td></tr><tr><td><code>comparison.php</code></td><td>Compare page</td></tr><tr><td><code>leaderboard.php</code></td><td>Leaderboard widget</td></tr></tbody></table><p><a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio →</a>, <a href="/builders.html" target="_blank" rel="noopener noreferrer">Builders →</a></p><h2 id="customer-documentation" tabindex="-1"><a class="header-anchor" href="#customer-documentation"><span>Customer documentation</span></a></h2><p>Pages users can read directly:</p><ul><li><a href="/customer-my-auctions.html" target="_blank" rel="noopener noreferrer">My Auctions</a></li><li><a href="/customer-wallet.html" target="_blank" rel="noopener noreferrer">My Wallet</a></li><li><a href="/customer-withdrawal.html" target="_blank" rel="noopener noreferrer">Withdrawal</a></li><li><a href="/customer-single-auction.html" target="_blank" rel="noopener noreferrer">Single Auction</a></li><li><a href="/customer-notifications.html" target="_blank" rel="noopener noreferrer">Notifications</a></li></ul>',60)])])}]]),n=JSON.parse('{"path":"/customer-overview.html","title":"Customer Experience Overview","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"My Account additions","slug":"my-account-additions","link":"#my-account-additions","children":[]},{"level":2,"title":"Single auction page","slug":"single-auction-page","link":"#single-auction-page","children":[]},{"level":2,"title":"Shop / archive","slug":"shop-archive","link":"#shop-archive","children":[]},{"level":2,"title":"Saved searches","slug":"saved-searches","link":"#saved-searches","children":[]},{"level":2,"title":"Favorites / Wishlist","slug":"favorites-wishlist","link":"#favorites-wishlist","children":[]},{"level":2,"title":"Comparison","slug":"comparison","link":"#comparison","children":[]},{"level":2,"title":"Messaging","slug":"messaging","link":"#messaging","children":[]},{"level":2,"title":"Print auction details","slug":"print-auction-details","link":"#print-auction-details","children":[]},{"level":2,"title":"Share","slug":"share","link":"#share","children":[]},{"level":2,"title":"Notifications","slug":"notifications","link":"#notifications","children":[]},{"level":2,"title":"Mobile experience","slug":"mobile-experience","link":"#mobile-experience","children":[]},{"level":2,"title":"Accessibility","slug":"accessibility","link":"#accessibility","children":[]},{"level":2,"title":"Templates to override","slug":"templates-to-override","link":"#templates-to-override","children":[]},{"level":2,"title":"Customer documentation","slug":"customer-documentation","link":"#customer-documentation","children":[]}],"git":{},"filePathRelative":"customer-overview.md"}')}}]);